// Lottie Web 库的占位文件
// 实际使用时可以从 https://cdnjs.cloudflare.com/ajax/libs/lottie-web/5.12.2/lottie.min.js 下载
// 或者使用 npm 安装 lottie-web 并打包

// 由于我们使用 SVG + CSS 动画替代，这里提供一个空实现
const lottie = {
  loadAnimation: function(options) {
    console.log('Lottie animation placeholder:', options.name || 'animation');
    return {
      play: () => {},
      pause: () => {},
      stop: () => {},
      setSpeed: () => {},
      goToAndPlay: () => {},
      goToAndStop: () => {},
      setDirection: () => {},
      destroy: () => {},
      addEventListener: () => {},
      removeEventListener: () => {}
    };
  },
  destroy: function() {},
  registerAnimation: function() {},
  setQuality: function() {},
  setSpeed: function() {},
  setLocationHref: function() {}
};

// 如果在浏览器环境中，挂载到 window
if (typeof window !== 'undefined') {
  window.lottie = lottie;
}
